sections.code_example:
def check_positive(n):
    if n <= 0:
        return "Not positive"
    return "Positive"

print(check_positive(-3))
print(check_positive(10))

def min_max(numbers):
    return min(numbers), max(numbers)

lo, hi = min_max([4, 1, 9, 2, 7])
print(lo)   # 1
print(hi)   # 9

